<?php
namespace Tests\Feature\Payouts;
use App\Domain\Payouts\Actions\CreatePayout;use App\Domain\Payouts\Actions\ProcessPayout;use App\Enums\PayoutStatus;use App\Enums\PayoutType;use App\Models\Cooperative;use App\Support\Tenancy\TenantContext;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class PayoutProviderEventTest extends TestCase{use RefreshDatabase;public function test_provider_event_is_idempotent():void{$cooperative=Cooperative::factory()->create();app(TenantContext::class)->set($cooperative);$payout=app(CreatePayout::class)->execute(['idempotency_key'=>'refund-001','type'=>PayoutType::MemberRefund,'amount_minor'=>10000,'beneficiary_name'=>'Member']);$payout->update(['status'=>PayoutStatus::Processing]);$action=app(ProcessPayout::class);$event=['provider_event_id'=>'evt-001','event_type'=>'paid','provider_reference'=>'provider-001'];$action->providerEvent($payout,$event);$action->providerEvent($payout,$event);$this->assertSame(PayoutStatus::Paid,$payout->refresh()->status);$this->assertDatabaseCount('payout_events',1);}}
